"use client"

import { useState, useEffect } from 'react';
import { JournalList } from './JournalList';
import { MarkdownEditor } from './MarkdownEditor';
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";

interface JournalEntry {
  id: string;
  title: string;
  content: string;
  createdAt: Date;
  updatedAt: Date;
  tags: string[];
}

export function Journal() {
  const [entries, setEntries] = useState<JournalEntry[]>([]);
  const [selectedEntry, setSelectedEntry] = useState<JournalEntry | null>(null);
  const [isNewEntryDialogOpen, setIsNewEntryDialogOpen] = useState(false);
  const [newEntryTitle, setNewEntryTitle] = useState('');

  // Load entries from localStorage on mount
  useEffect(() => {
    const savedEntries = localStorage.getItem('journalEntries');
    if (savedEntries) {
      setEntries(JSON.parse(savedEntries));
    }
  }, []);

  // Save entries to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem('journalEntries', JSON.stringify(entries));
  }, [entries]);

  const handleCreateNew = () => {
    console.log('handleCreateNew called');
    setIsNewEntryDialogOpen(true);
  };

  const handleCreateEntry = () => {
    if (!newEntryTitle.trim()) return;

    const newEntry: JournalEntry = {
      id: Date.now().toString(),
      title: newEntryTitle,
      content: '',
      createdAt: new Date(),
      updatedAt: new Date(),
      tags: [],
    };

    setEntries([...entries, newEntry]);
    setSelectedEntry(newEntry);
    setNewEntryTitle('');
    setIsNewEntryDialogOpen(false);
  };

  const handleSelectEntry = (entry: JournalEntry) => {
    setSelectedEntry(entry);
  };

  const handleSaveEntry = () => {
    if (!selectedEntry) return;

    const updatedEntries = entries.map(entry =>
      entry.id === selectedEntry.id
        ? { ...selectedEntry, updatedAt: new Date() }
        : entry
    );

    setEntries(updatedEntries);
    setSelectedEntry(null);
  };

  const handleContentChange = (content: string) => {
    if (!selectedEntry) return;
    setSelectedEntry({ ...selectedEntry, content });
  };

  return (
    <div className="flex h-full">
      <div className="w-80 border-r">
        <JournalList
          entries={entries}
          onSelectEntry={handleSelectEntry}
          onCreateNew={handleCreateNew}
        />
      </div>
      <div className="flex-1">
        {selectedEntry ? (
          <div className="flex flex-col h-full">
            <div className="p-4 border-b">
              <h2 className="text-2xl font-bold">{selectedEntry.title}</h2>
              <div className="text-sm text-muted-foreground">
                Last updated: {new Date(selectedEntry.updatedAt).toLocaleString()}
              </div>
            </div>
            <div className="flex-1">
              <MarkdownEditor
                content={selectedEntry.content}
                onChange={handleContentChange}
                onSave={handleSaveEntry}
              />
            </div>
          </div>
        ) : (
          <div className="flex items-center justify-center h-full text-muted-foreground">
            Select a journal entry or create a new one
          </div>
        )}
      </div>

      <Dialog open={isNewEntryDialogOpen} onOpenChange={setIsNewEntryDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Create New Journal Entry</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="title">Title</Label>
              <Input
                id="title"
                value={newEntryTitle}
                onChange={(e) => setNewEntryTitle(e.target.value)}
                placeholder="Enter journal entry title"
              />
            </div>
            <Button onClick={handleCreateEntry} className="w-full">
              Create Entry
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
} 